"""
This module contains the core game logic for Checkers.
"""

class Piece:
    def __init__(self, color, position):
        self.color = color
        self.position = position
        self.king = False

    def move(self, new_position):
        self.position = new_position

class Board:
    def __init__(self):
        self.squares = [[None] * 8 for _ in range(8)]
        self.init_board()

    def init_board(self):
        # Place pieces on the board
        colors = ['B', 'W']
        positions = [(i, j) if (i + j) % 2 == 1 else None for i in range(8) for j in range(8)]
        piece_positions = zip(colors * 4, positions)
        for color, position in piece_positions:
            if position is not None:
                self.squares[position[0]][position[1]] = Piece(color, position)

    def print_board(self):
        for row in self.squares:
            for square in row:
                if square:
                    print(square.color, end=" ")
                else:
                    print(".", end=" ")
            print()

    def is_valid_move(self, start, end):
        piece = self.squares[start[0]][start[1]]
        if not piece or piece.color != 'W':
            return False

        # Basic movement logic (can be expanded for full capture rules)
        row_diff = abs(start[0] - end[0])
        col_diff = abs(start[1] - end[1])

        if (row_diff == 1 and col_diff == 1) or (row_diff == 2 and col_diff == 2):
            return True
        return False

class CheckersGame:
    def __init__(self):
        self.board = Board()
        self.current_player = 'W'

    def take_turn(self):
        self.board.print_board()
        start, end = input(f"Player {self.current_player}, enter move (start-end): ").split('-')
        start = tuple(map(int, start.split(',')))
        end = tuple(map(int, end.split(',')))

        if self.board.is_valid_move(start, end):
            piece = self.board.squares[start[0]][start[1]]
            piece.move(end)
            # Update game state (e.g., capture logic)
            self.current_player = 'B' if self.current_player == 'W' else 'W'
        else:
            print("Invalid move. Please try again.")

def run():
    game = CheckersGame()
    while True:
        game.take_turn()

if __name__ == "__main__":
    run()
